class Solution(object):
    def largestPerimeter(self, nums):
        nums.sort()
        prefix = 0
        ans = -1
        for i, v in enumerate(nums):
            if i >= 2 and prefix > v:
                # All elements nums[0..i] form a valid polygon with longest side v
                ans = prefix + v
            prefix += v
        return ans
